#include <stdio.h>
#include <stdlib.h>

// Node for storing a non-zero element
typedef struct SparseNode {
 int row;
 int col;
 int value;
 struct SparseNode *next_row; // next in same column (downward)
 struct SparseNode *next_col; // next in same row (rightward)
} SparseNode;

// Sparse matrix structure with header arrays
typedef struct SparseMatrix {
 int rows;
 int cols;
 int numNonZero;
 SparseNode **row_head; // array of row header pointers
 SparseNode **col_head; // array of column header pointers
} SparseMatrix;

// Create an empty sparse matrix
SparseMatrix* createSparseMatrix(int rows, int cols) {
 SparseMatrix *mat = (SparseMatrix *)malloc(sizeof(SparseMatrix));
 mat->rows = rows;
 mat->cols = cols;
 mat->numNonZero = 0;
 mat->row_head = (SparseNode **)calloc(rows, sizeof(SparseNode *));
 mat->col_head = (SparseNode **)calloc(cols, sizeof(SparseNode *));
 return mat;
}

// Create a new sparse node
SparseNode* createNode(int row, int col, int value) {
 SparseNode *node = (SparseNode *)malloc(sizeof(SparseNode));
 node->row = row;
 node->col = col;
 node->value = value;
 node->next_row = NULL;
 node->next_col = NULL;
 return node;
}

// Insert a non-zero element into the sparse matrix
void insertElement(SparseMatrix *mat, int row, int col, int value) {
 if (value == 0) return; // do not store zeros
 if (row < 0 || row >= mat->rows || col < 0 || col >= mat->cols) return;

 SparseNode *node = createNode(row, col, value);

 // Insert into the row list (sorted by column)
 if (mat->row_head[row] == NULL || mat->row_head[row]->col > col) {
 node->next_col = mat->row_head[row];
 mat->row_head[row] = node;
 } else {
 SparseNode *temp = mat->row_head[row];
 while (temp->next_col != NULL && temp->next_col->col < col) {
 temp = temp->next_col;
 }
 node->next_col = temp->next_col;
 temp->next_col = node;
 }

 // Insert into the column list (sorted by row)
 if (mat->col_head[col] == NULL || mat->col_head[col]->row > row) {
 node->next_row = mat->col_head[col];
 mat->col_head[col] = node;
 } else {
 SparseNode *temp = mat->col_head[col];
 while (temp->next_row != NULL && temp->next_row->row < row) {
 temp = temp->next_row;
 }
 node->next_row = temp->next_row;
 temp->next_row = node;
 }

 mat->numNonZero++;
}

// Display the sparse matrix in dense (full) form
void displayMatrix(SparseMatrix *mat) {
 printf("Sparse Matrix (%d x %d) with %d non-zero elements:\n", 
 mat->rows, mat->cols, mat->numNonZero);
 for (int i = 0; i < mat->rows; i++) {
 SparseNode *curr = mat->row_head[i];
 for (int j = 0; j < mat->cols; j++) {
 if (curr != NULL && curr->col == j) {
 printf("%4d", curr->value);
 curr = curr->next_col;
 } else {
 printf("%4d", 0);
 }
 }
 printf("\n");
 }
}

// Display non-zero elements in triplet form
void displayTriplets(SparseMatrix *mat) {
 printf("Row Col Value\n");
 printf("--- --- -----\n");
 for (int i = 0; i < mat->rows; i++) {
 SparseNode *curr = mat->row_head[i];
 while (curr != NULL) {
 printf("%3d %3d %5d\n", curr->row, curr->col, curr->value);
 curr = curr->next_col;
 }
 }
}

// Transpose the sparse matrix
SparseMatrix* transposeSparse(SparseMatrix *mat) {
 SparseMatrix *trans = createSparseMatrix(mat->cols, mat->rows);

 // Traverse column-wise and insert with swapped indices
 for (int j = 0; j < mat->cols; j++) {
 SparseNode *curr = mat->col_head[j];
 while (curr != NULL) {
 insertElement(trans, curr->col, curr->row, curr->value);
 curr = curr->next_row;
 }
 }
 return trans;
}

// Add two sparse matrices
SparseMatrix* addSparse(SparseMatrix *A, SparseMatrix *B) {
 if (A->rows != B->rows || A->cols != B->cols) {
 printf("Error: Matrices must have same dimensions!\n");
 return NULL;
 }

 SparseMatrix *result = createSparseMatrix(A->rows, A->cols);

 // Process each row - merge the two row lists
 for (int i = 0; i < A->rows; i++) {
 SparseNode *p1 = A->row_head[i];
 SparseNode *p2 = B->row_head[i];

 while (p1 != NULL && p2 != NULL) {
 if (p1->col < p2->col) {
 insertElement(result, i, p1->col, p1->value);
 p1 = p1->next_col;
 } else if (p1->col > p2->col) {
 insertElement(result, i, p2->col, p2->value);
 p2 = p2->next_col;
 } else {
 // Same column - add values if non-zero
 if (p1->value + p2->value != 0) {
 insertElement(result, i, p1->col, p1->value + p2->value);
 }
 p1 = p1->next_col;
 p2 = p2->next_col;
 }
 }

 // Copy remaining elements from A
 while (p1 != NULL) {
 insertElement(result, i, p1->col, p1->value);
 p1 = p1->next_col;
 }
 // Copy remaining elements from B
 while (p2 != NULL) {
 insertElement(result, i, p2->col, p2->value);
 p2 = p2->next_col;
 }
 }
 return result;
}

// Free all memory
void freeSparseMatrix(SparseMatrix *mat) {
 if (mat == NULL) return;
 for (int i = 0; i < mat->rows; i++) {
 SparseNode *curr = mat->row_head[i];
 while (curr != NULL) {
 SparseNode *next = curr->next_col;
 free(curr);
 curr = next;
 }
 }
 free(mat->row_head);
 free(mat->col_head);
 free(mat);
}

// Main function demonstrating the implementation
int main() {
 // Create sparse matrix (4x5 example from theory)
 SparseMatrix *mat = createSparseMatrix(4, 5);

 // Insert non-zero elements
 insertElement(mat, 0, 2, 3);
 insertElement(mat, 0, 4, 4);
 insertElement(mat, 1, 2, 5);
 insertElement(mat, 1, 3, 7);
 insertElement(mat, 3, 1, 2);
 insertElement(mat, 3, 2, 6);

 printf("=== Original Matrix (Dense Form) ===\n");
 displayMatrix(mat);

 printf("\n=== Non-zero Elements (Triplet Form) ===\n");
 displayTriplets(mat);

 // Test transpose
 printf("\n=== Transpose Matrix ===\n");
 SparseMatrix *trans = transposeSparse(mat);
 displayMatrix(trans);

 // Test addition - create second matrix
 SparseMatrix *mat2 = createSparseMatrix(4, 5);
 insertElement(mat2, 0, 2, 1);
 insertElement(mat2, 1, 3, -2);
 insertElement(mat2, 2, 4, 3);

 printf("\n=== Second Matrix ===\n");
 displayMatrix(mat2);

 printf("\n=== Addition Result ===\n");
 SparseMatrix *sum = addSparse(mat, mat2);
 displayMatrix(sum);

 // Free memory
 freeSparseMatrix(mat);
 freeSparseMatrix(trans);
 freeSparseMatrix(mat2);
 freeSparseMatrix(sum);

 return 0;
}
